// Module: nc_ahb_to_sram
// Description: AHB-Lite to synchronous SRAM bridge with RAW merge and 1-cycle read wait.
// -----------------------------------------------------------------------------
module nc_ahb_to_sram #(
  // --------------------------------------------------------------------------
  // Parameter Declarations
  // --------------------------------------------------------------------------
  parameter integer g_AW = 16 // Address width
) (
  // --------------------------------------------------------------------------
  // Port Definitions
  // --------------------------------------------------------------------------
  input  wire            hclk,      // system bus clock
  input  wire            hreset_n,  // system bus reset
  input  wire            hsel,      // AHB peripheral select
  input  wire            hready,    // AHB ready input
  input  wire      [1:0] htrans,    // AHB transfer type
  input  wire      [2:0] hsize,     // AHB hsize
  input  wire            hwrite,    // AHB hwrite
  input  wire [g_AW-1:0] haddr,     // AHB address bus
  input  wire     [31:0] hwdata,    // AHB write data bus
  output wire            hreadyout, // AHB ready output to S->M mux
  output wire            hresp,     // AHB response
  output wire     [31:0] hrdata,    // AHB read data bus

  input  wire     [31:0] sramrdata, // SRAM read data
  output wire [g_AW-3:0] sramaddr,  // SRAM address
  output wire      [3:0] sramwen,   // SRAM write enable (active high)
  output wire     [31:0] sramwdata, // SRAM write data
  output wire            sramcs     // SRAM chip select (active high)
);

  // ----------------------------------------------------------
  // Internal state
  // ----------------------------------------------------------
  reg  [g_AW-3:0] wr_addr_buf;      // Write address buffer (data phase)
  reg       [3:0] wr_byte_en_buf;   // Byte-lane enables (data phase)
  reg             wr_addr_hit;      // Read address matches buffered write address
  reg      [31:0] wr_data_buf;      // Buffered write data (data phase)
  reg             wr_pending;       // Buffered write pending
  reg             wr_data_phase;    // Data-phase write qualifier

  // Sync SRAM read wait (1-cycle)
  reg             rd_wait;
  reg  [g_AW-3:0] rd_addr_lat;

  // ----------------------------------------------------------
  // AHB access qualifiers
  // ----------------------------------------------------------
  wire ahb_access   = htrans[1] && hsel && hready;
  wire ahb_wr       = ahb_access && hwrite;
  wire ahb_rd       = ahb_access && (!hwrite);
  wire ahb_rd_raw   = htrans[1] && hsel && (!hwrite);
  wire rd_overlap   = wr_data_phase && ahb_rd_raw;
  wire ahb_rd_valid = ahb_rd && (!rd_overlap);

  // ----------------------------------------------------------
  // SRAM access control
  // ----------------------------------------------------------
  wire ram_read     = ahb_rd_valid;
  wire wr_pending_nxt = (wr_pending | wr_data_phase) && ram_read;
  wire ram_write    = (wr_pending | wr_data_phase) && (!ram_read);

  // SRAM address: read address when reading (or during wait), otherwise buffered write addr
  assign sramaddr = (rd_wait)  ? rd_addr_lat :
                    (ahb_rd)   ? haddr[(g_AW-1):2] :
                                 wr_addr_buf;

  // SRAM chip select during read or write
  assign sramcs   = ram_read | ram_write | rd_wait;

  // SRAM write enable
  assign sramwen  = {4{ram_write}} & wr_byte_en_buf[3:0];

  // ----------------------------------------------------------
  // Byte lane decode
  // ----------------------------------------------------------
  wire is_byte = (hsize == 3'b000);
  wire is_half = (hsize == 3'b001);
  wire is_word = (hsize == 3'b010);

  wire byte_0  = is_byte && (haddr[1:0] == 2'b00);
  wire byte_1  = is_byte && (haddr[1:0] == 2'b01);
  wire byte_2  = is_byte && (haddr[1:0] == 2'b10);
  wire byte_3  = is_byte && (haddr[1:0] == 2'b11);

  wire half_0  = is_half && ~haddr[1];
  wire half_2  = is_half &&  haddr[1];

  wire byte_sel_0 = is_word || half_0 || byte_0;
  wire byte_sel_1 = is_word || half_0 || byte_1;
  wire byte_sel_2 = is_word || half_2 || byte_2;
  wire byte_sel_3 = is_word || half_2 || byte_3;

  // Address-phase byte lane strobe
  wire [3:0] wr_byte_en_nxt = { byte_sel_3 & ahb_wr,
                               byte_sel_2 & ahb_wr,
                               byte_sel_1 & ahb_wr,
                               byte_sel_0 & ahb_wr };

  // ----------------------------------------------------------
